uv run python -c "import pandas as pd, os, re; inp='uploads/result_analysis/COMP_FINAL_RESULT.xls'; out='outputs/failed_students_output.xlsx'; df=pd.read_excel(inp, header=None); records=[]; total=0
for i in range(len(df)-1):
    r0=df.iloc[i];
    c0=r0[0]; c1=r0[1] if 1 in r0.index else None
    if pd.notna(c1) and str(c1).strip()=='MarksO' and pd.notna(c0):
        roll=str(c0).strip();
        if re.fullmatch(r'\d+', roll):
            total+=1
            name_raw=df.iloc[i+1,0] if i+1 < len(df) else ''
            name=str(name_raw).strip() if pd.notna(name_raw) else ''
            if name.startswith('/'):
                name=name[1:].strip()
            status_cell=df.iloc[i,33] if 33 < df.shape[1] else None
            status=str(status_cell).strip().upper() if pd.notna(status_cell) else ''
            grades=[]
            if i+1 < len(df) and pd.notna(df.iloc[i+1,1]) and str(df.iloc[i+1,1]).strip()=='Grade':
                for v in df.iloc[i+1,2:31]:
                    if pd.notna(v):
                        g=str(v).strip().upper()
                        if g:
                            grades.append(g)
            failed = status in {'F','FAIL','FAILED'} or ('F' in grades)
            if failed:
                records.append({'RollNo':roll,'Name':name,'Status':'failed'})
os.makedirs('outputs', exist_ok=True)
out_df=pd.DataFrame(records, columns=['RollNo','Name','Status'])
out_df.to_excel(out, index=False)
print('TOTAL', total)
print('FAILED', len(out_df))
print('OUT', out)
"
